import { conjureFetch } from "conjure-lite";
/**
 * Get an SDK version.
 *
 * Requires third-party-application:view-standalone-sdk on the repository rid.
 */
export async function getSdk(ctx, repositoryRid, packageName, sdkVersion) {
  return conjureFetch(ctx, `/sdks/${repositoryRid}/${packageName}/${sdkVersion}`, "GET");
}